import { useEffect, useMemo, useState } from "react";
import api from "../api";

/** ========= Config ========= **/
const PAGE_SIZE = 10;
const STATUSES = ["ACTIVE", "INACTIVE"];

/** Chuẩn hoá Page<?> từ BE */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return {
        list: d?.content || [],
        pages: typeof d?.totalPages === "number" ? d.totalPages : 1,
    };
}

/** debounce nhỏ cho ô tìm kiếm */
function useDebounce(value, delay = 400) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

function emptyForm() {
    return {
        username: "",
        fullName: "",
        email: "",
        phone: "",
        role: "SALES",
        status: "ACTIVE",
        password: "",
        confirm: "",
        resetPassword: false,
    };
}

/** ========= Nhãn & nhóm quyền (hiển thị tiếng Việt) ========= **/
const PERM_LABELS = {
    CUSTOMER_READ: "Xem danh sách khách hàng",
    CUSTOMER_CREATE: "Tạo khách hàng mới",
    CUSTOMER_UPDATE: "Chỉnh sửa thông tin khách hàng",
    CUSTOMER_DELETE: "Xóa khách hàng",
    CUSTOMER_WRITE: "Ghi/Chỉnh sửa khách hàng",

    CONTRACT_READ: "Xem danh sách hợp đồng",
    CONTRACT_CREATE: "Tạo hợp đồng mới",
    CONTRACT_UPDATE: "Chỉnh sửa hợp đồng",
    CONTRACT_APPROVE: "Phê duyệt hợp đồng",
    CONTRACT_WRITE: "Ghi/Chỉnh sửa hợp đồng",

    PAYMENT_READ: "Xem thông tin thanh toán",
    PAYMENT_CREATE: "Tạo phiếu thu",
    PAYMENT_MARK_PAID: "Phê duyệt thanh toán / đánh dấu đã thu",
    PAYMENT_DELETE: "Xóa phiếu (chưa thanh toán)",
    PAYMENT_WRITE: "Ghi/Chỉnh sửa thanh toán",

    REPORT_VIEW: "Xem báo cáo tổng hợp",
    REPORT_EXPORT: "Xuất báo cáo",
    REPORT_FINANCE_VIEW: "Xem báo cáo tài chính",

    USER_MANAGE: "Quản lý người dùng",
    USER_READ: "Xem người dùng",
    USER_WRITE: "Chỉnh sửa người dùng",

    ROLE_READ: "Xem vai trò",
    ROLE_WRITE: "Chỉnh sửa vai trò",

    SYSTEM_CONFIG: "Cấu hình hệ thống",
    SYSTEM_AUDIT_VIEW: "Xem nhật ký hệ thống",
};
const groupOf = (code) => {
    if (code.startsWith("CUSTOMER_")) return "Quản lý khách hàng";
    if (code.startsWith("CONTRACT_")) return "Quản lý hợp đồng";
    if (code.startsWith("PAYMENT_")) return "Quản lý thanh toán";
    if (code.startsWith("REPORT_")) return "Báo cáo & Thống kê";
    if (code.startsWith("USER_")) return "Người dùng";
    if (code.startsWith("ROLE_")) return "Vai trò";
    if (code.startsWith("SYSTEM_")) return "Quản trị hệ thống";
    return "Khác";
};
const GROUP_ORDER = [
    "Quản lý khách hàng",
    "Quản lý hợp đồng",
    "Quản lý thanh toán",
    "Báo cáo & Thống kê",
    "Người dùng",
    "Vai trò",
    "Quản trị hệ thống",
    "Khác",
];
const permLabel = (c) => PERM_LABELS[c] || c;

/** ========= API helper ========= **/
async function fetchRoles() {
    try {
        const { data } = await api.get("/api/roles"); // List<String> hoặc List<{id,name}>
        // Chuẩn hoá danh sách name
        const names = Array.isArray(data)
            ? data.map((it) => (typeof it === "string" ? it : it?.name)).filter(Boolean)
            : [];
        return [...new Set(names)].sort();
    } catch {
        return ["ADMIN", "SALES", "ACCOUNTANT"];
    }
}
async function fetchAllPermissions() {
    try {
        const { data } = await api.get("/api/roles/permissions");
        return Array.isArray(data) ? data : [];
    } catch {
        return [];
    }
}
async function createCustomRole(name, permissions) {
    const { data } = await api.post("/api/roles", { name, permissions });
    return data; // RoleResponse
}
const getRoleById = (id) => api.get(`/api/roles/${id}`).then((r) => r.data);
const updateRole = (id, payload) => api.put(`/api/roles/${id}`, payload).then((r) => r.data);
const deleteRole = (id) => api.delete(`/api/roles/${id}`);
// khi backend chỉ có name:
async function fetchRoleDetailByName(name) {
    try {
        const r = await api.get("/api/roles", { params: { name } }); // nếu đã hỗ trợ trả detail
        if (r?.data?.id) return r.data;
    } catch {}
    try {
        const r = await api.get(`/api/roles/by-name/${encodeURIComponent(name)}`);
        return r.data;
    } catch {}
    throw new Error("Thiếu endpoint GET /api/roles?name= hoặc /api/roles/by-name/{name}");
}

/** =================== Component chính: Users =================== */
export default function Users() {
    const [rows, setRows] = useState([]);
    const [page, setPage] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [loading, setLoading] = useState(true);

    // filters
    const [q, setQ] = useState("");
    const dq = useDebounce(q, 450);
    const [role, setRole] = useState("");
    const [status, setStatus] = useState("");

    // modal user
    const [show, setShow] = useState(false);
    const [editing, setEditing] = useState(null);
    const [form, setForm] = useState(emptyForm());

    // danh sách roles từ BE
    const [roles, setRoles] = useState(["ADMIN", "SALES", "ACCOUNTANT"]);

    // modal quản lý vai trò
    const [showRoleMgr, setShowRoleMgr] = useState(false);

    useEffect(() => {
        (async () => {
            const rs = await fetchRoles();
            if (rs?.length) setRoles(rs);
        })();
    }, []);

    useEffect(() => {
        load();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [page, dq, role, status]);

    async function load() {
        setLoading(true);
        try {
            const { data } = await api.get("/api/users", {
                params: {
                    q: dq || undefined,
                    role: role || undefined,
                    status: status || undefined,
                    page,
                    size: PAGE_SIZE,
                    sort: "id,desc",
                },
            });
            const { list, pages } = normalizePage(data);
            setRows(
                list.map((u) => ({
                    id: u.id,
                    username: u.username,
                    fullName: u.fullName || u.name || "",
                    email: u.email || "",
                    phone: u.phone || "",
                    role: (u.role || "").toString().replace(/^ROLE_/, "") || "SALES",
                    status: u.active === false ? "INACTIVE" : "ACTIVE",
                }))
            );
            setTotalPages(pages);
        } catch (e) {
            console.error(e);
            setRows([]);
            setTotalPages(1);
        } finally {
            setLoading(false);
        }
    }

    function openCreate() {
        setEditing(null);
        setForm(emptyForm());
        setShow(true);
    }
    function openEdit(row) {
        setEditing(row);
        setForm({
            username: row.username || "",
            fullName: row.fullName || "",
            email: row.email || "",
            phone: row.phone || "",
            role: row.role || "SALES",
            status: row.status || "ACTIVE",
            password: "",
            confirm: "",
            resetPassword: false,
        });
        setShow(true);
    }

    async function save(e) {
        e.preventDefault();
        try {
            if (!editing) {
                if (!form.password?.trim()) return alert("Mật khẩu không được để trống");
                if (form.password !== form.confirm) return alert("Xác nhận mật khẩu không khớp");
                const payload = {
                    username: form.username?.trim(),
                    fullName: form.fullName?.trim(),
                    email: form.email?.trim(),
                    phone: form.phone?.trim(),
                    password: form.password,
                    roleName: form.role,
                    active: form.status === "ACTIVE",
                };
                await api.post("/api/users", payload);
            } else {
                const payload = {
                    fullName: form.fullName?.trim(),
                    email: form.email?.trim(),
                    phone: form.phone?.trim(),
                    roleName: form.role,
                    active: form.status === "ACTIVE",
                };
                if (form.resetPassword) {
                    if (!form.password?.trim()) return alert("Nhập mật khẩu mới");
                    if (form.password !== form.confirm) return alert("Xác nhận mật khẩu không khớp");
                    payload.password = form.password;
                }
                await api.put(`/api/users/${editing.id}`, payload);
            }
            setShow(false);
            if (rows.length === 0 && page > 0) setPage((p) => p - 1);
            await load();
            alert(editing ? "Đã cập nhật người dùng" : "Đã tạo người dùng");
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                (typeof err?.response?.data === "object"
                    ? Object.values(err.response.data).join("; ")
                    : "") ||
                "Lưu người dùng thất bại";
            alert(msg);
        }
    }

    async function remove(row) {
        if (!window.confirm(`Xoá người dùng ${row.username}?`)) return;
        try {
            await api.delete(`/api/users/${row.id}`);
            if (rows.length === 1 && page > 0) setPage((p) => p - 1);
            else await load();
            alert("Đã xoá");
        } catch (err) {
            const msg =
                err?.response?.data?.message ||
                err?.response?.data?.error ||
                "Xoá người dùng thất bại";
            alert(msg);
        }
    }

    return (
        <div className="space-y-4">
            {/* Header + Filters */}
            <div className="flex flex-col gap-3 md:flex-row md:items-end md:justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Người dùng & Phân quyền</h2>
                    <p className="text-sm text-slate-500">Quản trị viên có thể quản lý người dùng</p>
                </div>
                <div className="flex flex-wrap items-end gap-2">
                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Tìm kiếm</label>
                        <input
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow w-64"
                            placeholder="Tên đăng nhập / Họ tên / Email / SĐT…"
                            value={q}
                            onChange={(e) => {
                                setQ(e.target.value);
                                setPage(0);
                            }}
                        />
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Vai trò</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={role}
                            onChange={(e) => {
                                setRole(e.target.value);
                                setPage(0);
                            }}
                        >
                            <option value="">Tất cả</option>
                            {roles.map((r) => (
                                <option key={r} value={r}>
                                    {r}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div className="flex flex-col">
                        <label className="text-xs text-slate-500 mb-1">Trạng thái</label>
                        <select
                            className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            value={status}
                            onChange={(e) => {
                                setStatus(e.target.value);
                                setPage(0);
                            }}
                        >
                            <option value="">Tất cả</option>
                            {STATUSES.map((s) => (
                                <option key={s} value={s}>
                                    {s}
                                </option>
                            ))}
                        </select>
                    </div>

                    <button
                        onClick={openCreate}
                        className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 ml-auto"
                    >
                        Thêm người dùng
                    </button>
                </div>
            </div>

            {/* Bảng */}
            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Tên đăng nhập</th>
                            <th className="px-4 py-3 text-left">Họ tên</th>
                            <th className="px-4 py-3 text-left">Email</th>
                            <th className="px-4 py-3 text-left">Điện thoại</th>
                            <th className="px-4 py-3 text-left">Vai trò</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Đang tải…
                                </td>
                            </tr>
                        ) : rows.length === 0 ? (
                            <tr>
                                <td className="px-4 py-6" colSpan={7}>
                                    Chưa có dữ liệu
                                </td>
                            </tr>
                        ) : (
                            rows.map((u) => (
                                <tr key={u.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{u.username}</td>
                                    <td className="px-4 py-3">{u.fullName || "-"}</td>
                                    <td className="px-4 py-3">{u.email || "-"}</td>
                                    <td className="px-4 py-3">{u.phone || "-"}</td>
                                    <td className="px-4 py-3">{u.role}</td>
                                    <td className="px-4 py-3">
                      <span
                          className={
                              "px-2 py-0.5 rounded-full text-xs " +
                              (u.status === "ACTIVE"
                                  ? "bg-emerald-100 text-emerald-700"
                                  : "bg-slate-100 text-slate-700")
                          }
                      >
                        {u.status}
                      </span>
                                    </td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button
                                                onClick={() => openEdit(u)}
                                                className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                            >
                                                Sửa
                                            </button>
                                            <button
                                                onClick={() => remove(u)}
                                                className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                            >
                                                Xóa
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            ))
                        )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Pagination */}
            <div className="flex gap-2 justify-center">
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => Math.max(0, p - 1))}
                    disabled={page <= 0}
                >
                    ← Trước
                </button>
                <div className="px-3 py-1.5 text-sm">
                    Trang {page + 1}/{totalPages}
                </div>
                <button
                    className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                    onClick={() => setPage((p) => p + 1)}
                    disabled={page + 1 >= totalPages}
                >
                    Sau →
                </button>
            </div>

            {/* Modal Thêm/Sửa user */}
            {show && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl max-h-[90vh] bg-white rounded-2xl shadow-xl border border-indigo-100 flex flex-col">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">
                                {editing ? "Sửa người dùng" : "Thêm người dùng"}
                            </div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={() => setShow(false)}>
                                Đóng
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-5">
                            <form id="userForm" onSubmit={save} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div>
                                    <label className="text-sm text-slate-600">Tên đăng nhập</label>
                                    <input
                                        required
                                        disabled={!!editing}
                                        value={form.username}
                                        onChange={(e) => setForm((f) => ({ ...f, username: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Họ tên</label>
                                    <input
                                        required
                                        value={form.fullName}
                                        onChange={(e) => setForm((f) => ({ ...f, fullName: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Email</label>
                                    <input
                                        required
                                        type="email"
                                        value={form.email}
                                        onChange={(e) => setForm((f) => ({ ...f, email: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Điện thoại</label>
                                    <input
                                        value={form.phone}
                                        onChange={(e) => setForm((f) => ({ ...f, phone: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    />
                                </div>

                                {/* Vai trò + nút mở modal quản lý vai trò */}
                                <div className="flex flex-col">
                                    <label className="text-sm text-slate-600">Vai trò</label>
                                    <div className="flex gap-2">
                                        <select
                                            value={form.role}
                                            onChange={(e) => setForm((f) => ({ ...f, role: e.target.value }))}
                                            className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                        >
                                            {roles.map((r) => (
                                                <option key={r} value={r}>
                                                    {r}
                                                </option>
                                            ))}
                                        </select>
                                        <button
                                            type="button"
                                            onClick={() => setShowRoleMgr(true)}
                                            className="px-3 py-2 rounded-lg border bg-white hover:bg-slate-50"
                                        >
                                            Thêm vai trò
                                        </button>
                                    </div>
                                </div>

                                <div>
                                    <label className="text-sm text-slate-600">Trạng thái</label>
                                    <select
                                        value={form.status}
                                        onChange={(e) => setForm((f) => ({ ...f, status: e.target.value }))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    >
                                        {STATUSES.map((s) => (
                                            <option key={s} value={s}>
                                                {s}
                                            </option>
                                        ))}
                                    </select>
                                </div>

                                {/* Mật khẩu */}
                                {!editing ? (
                                    <>
                                        <div>
                                            <label className="text-sm text-slate-600">Mật khẩu</label>
                                            <input
                                                type="password"
                                                value={form.password}
                                                onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                                                className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                                required
                                            />
                                        </div>
                                        <div>
                                            <label className="text-sm text-slate-600">Xác nhận mật khẩu</label>
                                            <input
                                                type="password"
                                                value={form.confirm}
                                                onChange={(e) => setForm((f) => ({ ...f, confirm: e.target.value }))}
                                                className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                                required
                                            />
                                        </div>
                                    </>
                                ) : (
                                    <>
                                        <div className="md:col-span-2 flex items-center gap-2">
                                            <input
                                                id="resetPw"
                                                type="checkbox"
                                                checked={form.resetPassword}
                                                onChange={(e) => setForm((f) => ({ ...f, resetPassword: e.target.checked }))}
                                            />
                                            <label htmlFor="resetPw" className="text-sm text-slate-600 select-none">
                                                Đặt mật khẩu mới
                                            </label>
                                        </div>
                                        {form.resetPassword && (
                                            <>
                                                <div>
                                                    <label className="text-sm text-slate-600">Mật khẩu mới</label>
                                                    <input
                                                        type="password"
                                                        value={form.password}
                                                        onChange={(e) => setForm((f) => ({ ...f, password: e.target.value }))}
                                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                                        required
                                                    />
                                                </div>
                                                <div>
                                                    <label className="text-sm text-slate-600">Xác nhận mật khẩu</label>
                                                    <input
                                                        type="password"
                                                        value={form.confirm}
                                                        onChange={(e) => setForm((f) => ({ ...f, confirm: e.target.value }))}
                                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                                        required
                                                    />
                                                </div>
                                            </>
                                        )}
                                    </>
                                )}
                            </form>
                        </div>

                        <div className="p-4 border-t flex justify-end gap-2">
                            <button
                                type="button"
                                className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                onClick={() => setShow(false)}
                            >
                                Huỷ
                            </button>
                            <button form="userForm" className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">
                                Lưu
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Modal QUẢN LÝ VAI TRÒ — CRUD đầy đủ */}
            {showRoleMgr && (
                <RoleManagerModal
                    open={showRoleMgr}
                    onClose={() => setShowRoleMgr(false)}
                    onPick={(roleName) => {
                        setForm((f) => ({ ...f, role: roleName })); // gán vào form user
                        setRoles((prev) => (prev.includes(roleName) ? prev : [...prev, roleName].sort()));
                        setShowRoleMgr(false);
                    }}
                />
            )}
        </div>
    );
}

/** =================== Modal Quản lý vai trò (gộp trong file) =================== */
function RoleManagerModal({ open, onClose, onPick }) {
    const [roles, setRoles] = useState([]);     // [{id?, name}]
    const [allPerms, setAllPerms] = useState([]); // string[]
    const [loading, setLoading] = useState(true);

    const [q, setQ] = useState("");

    const [editing, setEditing] = useState(null); // RoleResponse | null
    const [formName, setFormName] = useState("");
    const [picked, setPicked] = useState([]); // string[]
    const [saving, setSaving] = useState(false);

    useEffect(() => {
        if (!open) return;
        (async () => {
            setLoading(true);
            try {
                const [rs, perms] = await Promise.all([fetchRoles(), fetchAllPermissions()]);
                setRoles(rs.map((n) => ({ name: n }))); // chuẩn hoá [{name}]
                setAllPerms(perms || []);
            } finally {
                setLoading(false);
            }
        })();
    }, [open]);

    const filtered = useMemo(() => {
        const k = q.trim().toLowerCase();
        if (!k) return roles;
        return roles.filter((r) => r.name.toLowerCase().includes(k));
    }, [q, roles]);

    function resetForm() {
        setEditing(null);
        setFormName("");
        setPicked([]);
    }
    function openCreate() {
        resetForm();
    }
    async function openEdit(r) {
        try {
            const detail = await fetchRoleDetailByName(r.name); // cần endpoint theo name
            setEditing(detail);
            setFormName(detail.name);
            setPicked(detail.permissions || []);
        } catch (e) {
            alert(e.message || "Không lấy được chi tiết vai trò");
        }
    }

    function toggle(code) {
        setPicked((prev) => (prev.includes(code) ? prev.filter((c) => c !== code) : [...prev, code]));
    }
    const selectAll = () => setPicked(allPerms.slice());
    const clearAll = () => setPicked([]);

    async function save() {
        if (!formName.trim()) return alert("Nhập tên vai trò");
        if (picked.length === 0) return alert("Chọn ít nhất 1 quyền");
        setSaving(true);
        try {
            if (!editing) {
                const created = await createCustomRole(formName.trim(), picked);
                setRoles((prev) =>
                    [...prev.map((x) => ({ name: x.name })), { name: created.name }].sort((a, b) =>
                        a.name.localeCompare(b.name)
                    )
                );
                onPick && onPick(created.name);
                resetForm();
                alert("Đã tạo vai trò");
            } else {
                const updated = await updateRole(editing.id, { name: formName.trim(), permissions: picked });
                setRoles((prev) =>
                    prev
                        .map((x) => ({ name: x.name === editing.name ? updated.name : x.name }))
                        .sort((a, b) => a.name.localeCompare(b.name))
                );
                onPick && onPick(updated.name);
                resetForm();
                alert("Đã lưu thay đổi");
            }
        } catch (err) {
            alert(err?.response?.data?.message || err?.response?.data?.error || "Lưu vai trò thất bại");
        } finally {
            setSaving(false);
        }
    }

    async function remove(r) {
        if (!window.confirm(`Xoá vai trò “${r.name}”?`)) return;
        try {
            const detail = await fetchRoleDetailByName(r.name);
            await deleteRole(detail.id);
            setRoles((prev) => prev.filter((x) => x.name !== r.name));
            if (editing && editing.name === r.name) resetForm();
            alert("Đã xoá");
        } catch (err) {
            alert(err?.response?.data?.message || err?.response?.data?.error || "Xoá vai trò thất bại");
        }
    }

    if (!open) return null;

    return (
        <div className="fixed inset-0 z-50 bg-black/40 grid place-items-center p-4">
            <div className="w-full max-w-5xl max-h-[90vh] bg-white rounded-2xl shadow-xl border border-indigo-100 flex flex-col">
                {/* header */}
                <div className="p-5 border-b flex items-center justify-between">
                    <div className="font-semibold">Quản lý vai trò</div>
                    <button className="text-slate-500 hover:text-slate-700" onClick={onClose}>
                        Đóng
                    </button>
                </div>

                {/* content */}
                <div className="flex-1 overflow-y-auto p-5 grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Bảng vai trò */}
                    <div className="bg-white rounded-xl border border-indigo-100">
                        <div className="p-3 border-b flex items-end gap-2">
                            <div className="flex flex-col grow">
                                <label className="text-xs text-slate-500 mb-1">Tìm kiếm vai trò</label>
                                <input
                                    value={q}
                                    onChange={(e) => setQ(e.target.value)}
                                    className="px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                    placeholder="Nhập tên vai trò…"
                                />
                            </div>
                            <button
                                onClick={openCreate}
                                className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700"
                            >
                                + Thêm
                            </button>
                        </div>
                        <div className="p-0">
                            <table className="min-w-full text-sm">
                                <thead className="bg-indigo-50 text-slate-600">
                                <tr>
                                    <th className="px-4 py-2 text-left">Tên vai trò</th>
                                    <th className="px-4 py-2 text-right">Thao tác</th>
                                </tr>
                                </thead>
                                <tbody className="divide-y">
                                {loading ? (
                                    <tr>
                                        <td className="px-4 py-6" colSpan={2}>
                                            Đang tải…
                                        </td>
                                    </tr>
                                ) : filtered.length === 0 ? (
                                    <tr>
                                        <td className="px-4 py-6" colSpan={2}>
                                            Không có vai trò
                                        </td>
                                    </tr>
                                ) : (
                                    filtered.map((r) => (
                                        <tr key={r.name} className="hover:bg-indigo-50/40">
                                            <td className="px-4 py-2">{r.name}</td>
                                            <td className="px-4 py-2 text-right">
                                                <div className="inline-flex gap-2">
                                                    <button
                                                        onClick={() => onPick && onPick(r.name)}
                                                        className="px-2 py-1 rounded bg-emerald-50 text-emerald-700 hover:bg-emerald-100"
                                                    >
                                                        Chọn
                                                    </button>
                                                    <button
                                                        onClick={() => openEdit(r)}
                                                        className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100"
                                                    >
                                                        Sửa
                                                    </button>
                                                    <button
                                                        onClick={() => remove(r)}
                                                        className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                                    >
                                                        Xoá
                                                    </button>
                                                </div>
                                            </td>
                                        </tr>
                                    ))
                                )}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    {/* Form tạo/sửa */}
                    <div className="bg-white rounded-xl border border-indigo-100 p-4">
                        <div className="font-medium mb-3">{editing ? "Sửa vai trò" : "Thêm vai trò"}</div>

                        <div className="mb-4">
                            <label className="text-sm text-slate-600">Tên vai trò</label>
                            <input
                                value={formName}
                                onChange={(e) => setFormName(e.target.value)}
                                placeholder="VD: MANAGER, SUPPORT…"
                                className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                            />
                        </div>

                        <div className="flex items-center gap-2 mb-2">
                            <div className="font-medium">Quyền</div>
                            <button
                                type="button"
                                onClick={selectAll}
                                className="px-2 py-1 rounded bg-slate-100 hover:bg-slate-200 text-xs"
                            >
                                Chọn tất cả
                            </button>
                            <button
                                type="button"
                                onClick={clearAll}
                                className="px-2 py-1 rounded bg-slate-100 hover:bg-slate-200 text-xs"
                            >
                                Bỏ hết
                            </button>
                        </div>

                        <div className="space-y-3 max-h-[46vh] overflow-y-auto pr-1">
                            {GROUP_ORDER.map((g) => {
                                const items = allPerms.filter((c) => groupOf(c) === g);
                                if (!items.length) return null;
                                return (
                                    <div key={g} className="rounded-lg border border-indigo-100 bg-white p-3">
                                        <div className="font-medium mb-2">{g}</div>
                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                                            {items.map((code) => {
                                                const checked = picked.includes(code);
                                                return (
                                                    <label key={code} className="flex items-center gap-2">
                                                        <input type="checkbox" checked={checked} onChange={() => toggle(code)} />
                                                        <span>{permLabel(code)}</span>
                                                    </label>
                                                );
                                            })}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>

                        <div className="pt-4 flex justify-end gap-2">
                            <button
                                onClick={save}
                                disabled={saving}
                                className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-60"
                            >
                                {editing ? "Lưu thay đổi" : "Tạo vai trò"}
                            </button>
                        </div>
                    </div>
                </div>

                {/* footer */}
                <div className="p-4 border-t flex justify-end gap-2">
                    <button
                        type="button"
                        className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                        onClick={onClose}
                    >
                        Đóng
                    </button>
                </div>
            </div>
        </div>
    );
}
